  "sourcesContent": ["\r\n.page { display:flex;flex-direction:column;gap:24px; }\r\n.page-header { display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:12px; }\r\n.page-sub { color:var(--text-secondary);margin-top:4px; }\r\n.filters { display:flex;align-items:center;gap:8px;flex-wrap:wrap; }\r\n.search-box { display:flex;align-items:center;gap:8px;background:white;border:1px solid var(--border);border-radius:var(--radius-sm);padding:7px 12px;font-family:inherit; }\r\n.search-box input { border:none;outline:none;font-size:13px;font-family:inherit;min-width:180px; }\r\n.tab { padding:6px 14px;border-radius:var(--radius-sm);font-size:12px;font-weight:600;border:none;cursor:pointer;background:transparent;color:var(--text-secondary);transition:all 0.15s; }\r\n.tab.active { background:var(--orange);color:white; }\r\n.grid { display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:16px; }\r\n.card { padding:22px;background:white;border-radius:var(--radius-lg);border:1px solid var(--border);transition:all 0.2s;box-shadow:var(--shadow-card); }\r\n.card:hover { box-shadow:var(--shadow-hover);transform:translateY(-2px); }\r\n.card-top { display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px; }\r\n.card-icon { width:42px;height:42px;border-radius:11px;display:flex;align-items:center;justify-content:center; }\r\n.card-name { font-family:\"Plus Jakarta Sans\",sans-serif;font-size:15px;font-weight:700;margin-bottom:4px; }\r\n.card-meta { font-size:12px;color:var(--text-secondary); }\r\n.card-progress { margin:14px 0 8px; }\r\n.card-footer { display:flex;align-items:center;justify-content:space-between;margin-top:14px;padding-top:12px;border-top:1px solid var(--border); }\r\n.actions { display:flex;gap:6px; }\r\n.empty { text-align:center;padding:60px 20px;color:var(--text-muted); }\r\n.empty svg { margin:0 auto 12px;display:block;opacity:0.3; }\r\n\r\n"],
